package watcher

// ChangeSet contains files that were added, modified, or deleted.
type ChangeSet struct {
	Added    []string
	Modified []string
	Deleted  []string
}

// Watcher tracks file changes in a directory.
type Watcher struct {
	dir   string
	state map[string]FileInfo
}

// NewWatcher creates a watcher for the given directory.
func NewWatcher(dir string) *Watcher {
	return &Watcher{dir: dir, state: make(map[string]FileInfo)}
}

// Check scans the directory and returns changes since the last check.
func (w *Watcher) Check() (*ChangeSet, error) {
	files, err := ScanDir(w.dir)
	if err != nil {
		return nil, err
	}

	cs := &ChangeSet{}
	current := make(map[string]FileInfo, len(files))

	for _, f := range files {
		current[f.Path] = f
		prev, exists := w.state[f.Path]
		if !exists {
			cs.Added = append(cs.Added, f.Path)
		} else if prev.Checksum != f.Checksum {
			cs.Modified = append(cs.Modified, f.Path)
		}
	}

	for path := range w.state {
		if _, exists := current[path]; !exists {
			cs.Deleted = append(cs.Deleted, path)
		}
	}

	w.state = current
	return cs, nil
}

package watcher

import (
	"os"
	"path/filepath"
	"testing"
)

func TestWatcherDetectsNewFile(t *testing.T) {
	dir := t.TempDir()
	w := NewWatcher(dir)

	// First scan: empty
	cs, err := w.Check()
	if err != nil {
		t.Fatal(err)
	}
	if len(cs.Added) != 0 {
		t.Fatalf("expected 0 added, got %d", len(cs.Added))
	}

	// Create a file
	os.WriteFile(filepath.Join(dir, "hello.txt"), []byte("hello"), 0644)

	cs, err = w.Check()
	if err != nil {
		t.Fatal(err)
	}
	if len(cs.Added) != 1 {
		t.Fatalf("expected 1 added, got %d", len(cs.Added))
	}
}

func TestWatcherDetectsModification(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "data.txt")
	os.WriteFile(path, []byte("version1"), 0644)

	w := NewWatcher(dir)
	w.Check() // initial scan

	os.WriteFile(path, []byte("version2"), 0644)

	cs, err := w.Check()
	if err != nil {
		t.Fatal(err)
	}
	if len(cs.Modified) != 1 {
		t.Fatalf("expected 1 modified, got %d", len(cs.Modified))
	}
}

func TestWatcherDetectsDeletion(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "temp.txt")
	os.WriteFile(path, []byte("temp"), 0644)

	w := NewWatcher(dir)
	w.Check()

	os.Remove(path)

	cs, err := w.Check()
	if err != nil {
		t.Fatal(err)
	}
	if len(cs.Deleted) != 1 {
		t.Fatalf("expected 1 deleted, got %d", len(cs.Deleted))
	}
}
